let message=msg
msg={}
msg.data.error='there is no such a document in db'
msg.data=message.data
return msg;

let buf = null;
msg.uibuildername ="ui"
if (Buffer.isBuffer(msg.payload)) {
    buf = msg.payload;
}
else if (msg.req && msg.req.rawBody && Buffer.isBuffer(msg.req.rawBody)) {
    buf = msg.req.rawBody;
}
else if (typeof msg.payload === 'string') {
    buf = Buffer.from(msg.payload, 'binary');
    node.warn('Payload arrived as string; converted using latin1. Prefer application/octet-stream to avoid corruption.');
} else {
    node.error('❌ Payload is not Buffer/String and no rawBody present');
    return null;
}

if (buf.length < 4 || buf[0] !== 0x50 || buf[1] !== 0x4B) {
    node.warn('⚠️ Payload does not start with PK (ZIP). Check Content-Type or middleware.');
}

msg.payload = buf;
msg.filename = "/data/uibuilder/backend-dist.zip";
return msg;

msg.statusCode = 200;
msg.headers = { "Content-Type": "text/plain; charset=utf-8" };
msg.payload = "OK";
return msg;

const name = msg.uibuildername;

const file = `/data/uibuilder/${name}/src/index.html`;

msg.command =
    `sh -c '[ -f "${file}" ] || { echo "index.html not found: ${file}" >&2; exit 1; }; ` +
    `sed -E -i "s#(src|href)=\\\"/assets/#\\\\1=\\\"/${name}/assets/#g" "${file}"'`;

return msg;

// Extract msg.type from wherever uibuilder puts it
if (!msg.type && msg.payload && typeof msg.payload === 'object') {
    if (msg.payload.type) msg.type = msg.payload.type;
}

// Extract msg.data from payload if not directly available
if (!msg.data && msg.payload && typeof msg.payload === 'object' && msg.payload.data) {
    msg.data = msg.payload.data;
}

// Extract msg.route from payload if not directly available
if (!msg.route && msg.payload && typeof msg.payload === 'object' && msg.payload.route) {
    msg.route = msg.payload.route;
}

// Extract _token from payload if not directly available
if (!msg._token && msg.payload && typeof msg.payload === 'object' && msg.payload._token) {
    msg._token = msg.payload._token;
}

// Extract auth from payload if not directly available
if (!msg.auth && msg.payload && typeof msg.payload === 'object' && msg.payload.auth) {
    msg.auth = msg.payload.auth;
}

return msg;

// FR-GI-01 — RFC 9279 api-catalog discovery
// Returns an RFC 9264 JSON Linkset pointing to the OpenAPI document.
const req = msg.req || {};
const proto = (req.headers && req.headers['x-forwarded-proto']) || req.protocol || 'https';
const host = (req.headers && (req.headers['x-forwarded-host'] || req.headers.host)) || 'localhost';
const base = proto + '://' + host;

const linkset = {
    linkset: [
        {
            anchor: base + '/',
            'service-desc': [
                {
                    href: base + '/api/openapi.json',
                    type: 'application/vnd.oai.openapi+json'
                }
            ],
            'service-doc': [
                {
                    href: base + '/api/openapi.json',
                    type: 'application/vnd.oai.openapi+json',
                    title: 'FAP DCM OpenAPI 3.0 description'
                }
            ]
        }
    ]
};

msg.headers = {
    'Content-Type': 'application/linkset+json',
    'Cache-Control': 'public, max-age=300'
};
msg.payload = linkset;
return msg;

// FR-GI-01 — OpenAPI 3.0 description of the FAP DCM public surface.
// Scope is intentionally minimal: the discovery endpoints + a reference to the
// uibuilder websocket channel through which the bulk of FR-ACM / FR-SR / FR-CR
// operations are dispatched. Full per-message schemas can be added incrementally.

const req = msg.req || {};
const proto = (req.headers && req.headers['x-forwarded-proto']) || req.protocol || 'https';
const host = (req.headers && (req.headers['x-forwarded-host'] || req.headers.host)) || 'localhost';
const base = proto + '://' + host;

const doc = {
    openapi: '3.0.3',
    info: {
        title: 'FAP DCM — Decentralized Catalogue Management API',
        description: 'Machine-readable API description for the FAP DCM, discoverable via RFC 9279 /.well-known/api-catalog. Business operations (Asset Crawler, Schema Registry, Catalogue Registry, Access Control) are dispatched primarily through a uibuilder websocket channel; REST endpoints listed here expose discovery metadata and health checks.',
        version: '1.0.0',
        contact: {
            name: 'facis GmbH — FAP DCM implementation'
        },
        license: {
            name: 'See project LICENSE'
        }
    },
    servers: [
        { url: base, description: 'Current deployment' }
    ],
    tags: [
        { name: 'Discovery', description: 'RFC 9279 discovery endpoints' },
        { name: 'Realtime',  description: 'uibuilder websocket message surface (FR-ACM / FR-SR / FR-CR / FR-AC)' }
    ],
    paths: {
        '/.well-known/api-catalog': {
            get: {
                tags: ['Discovery'],
                summary: 'RFC 9279 api-catalog — returns linkset pointing to this OpenAPI document',
                responses: {
                    '200': {
                        description: 'RFC 9264 linkset',
                        content: {
                            'application/linkset+json': {
                                schema: { type: 'object' }
                            }
                        }
                    }
                }
            }
        },
        '/api/openapi.json': {
            get: {
                tags: ['Discovery'],
                summary: 'OpenAPI 3.0 description of the FAP DCM API',
                responses: {
                    '200': {
                        description: 'OpenAPI 3.0 JSON',
                        content: {
                            'application/vnd.oai.openapi+json': {
                                schema: { type: 'object' }
                            }
                        }
                    }
                }
            }
        }
    },
    components: {
        schemas: {
            UiBuilderEnvelope: {
                type: 'object',
                description: 'Envelope for uibuilder websocket messages. The type field names the operation (e.g. registerRemoteCatalog, startHarvest, saveAssetType, listRoles). The data field carries operation-specific payload. All operations are subject to FR-AC-01 role checks.',
                required: ['type'],
                properties: {
                    type: { type: 'string', example: 'registerRemoteCatalog' },
                    auth: { type: 'object', description: 'Session bearer / API key; injected by FE' },
                    data: { type: 'object', description: 'Operation-specific payload' }
                }
            }
        }
    },
    'x-realtime-channel': {
        transport: 'uibuilder over socket.io',
        path: '/uibuilder',
        envelopeSchema: '#/components/schemas/UiBuilderEnvelope',
        notes: 'Frontend src/services/uibuilder.service.js ROUTE_MAP enumerates all supported msg.type values and their target backend modules.'
    }
};

msg.headers = {
    'Content-Type': 'application/vnd.oai.openapi+json; charset=utf-8',
    'Cache-Control': 'public, max-age=300'
};
msg.payload = doc;
return msg;
